window.addEventListener("scroll",function(){if(window.scrollY>180){document.body.classList.add("scrolled")}else{document.body.classList.remove("scrolled")}});document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".is-style-group-horizontal-scroll-btns").forEach(content=>{if(content.children.length>1){const rightBtn=document.createElement("button");rightBtn.classList.add("scrolling-button","scrolling-button--right");rightBtn.innerHTML="→";rightBtn.disabled=false;const leftBtn=document.createElement("button");leftBtn.classList.add("scrolling-button","scrolling-button--left");leftBtn.innerHTML="←";leftBtn.disabled=true;const buttonContainer=document.createElement("div");buttonContainer.classList.add("scrolling-button-container");buttonContainer.appendChild(leftBtn);buttonContainer.appendChild(rightBtn);content.parentNode.insertBefore(buttonContainer,content);function getScrollStep(){return window.innerWidth<768?400:288}rightBtn.addEventListener("click",()=>{const scrollContent=content;const scrollStep=getScrollStep();scrollContent.scrollLeft+=scrollStep;leftBtn.disabled=false;if(scrollContent.scrollWidth-scrollContent.scrollLeft-scrollContent.clientWidth<=0){rightBtn.disabled=true}});leftBtn.addEventListener("click",()=>{const scrollContent=content;const scrollStep=getScrollStep();scrollContent.scrollLeft-=scrollStep;rightBtn.disabled=false;if(scrollContent.scrollLeft<=0){leftBtn.disabled=true}})}})});document.addEventListener("DOMContentLoaded",event=>{const sliders=document.querySelectorAll(".is-style-group-horizontal-scroll");let isDown=false;let startX;let scrollLeft;sliders.forEach(slider=>{slider.addEventListener("mousedown",e=>{isDown=true;slider.classList.add("active");startX=e.pageX-slider.offsetLeft;scrollLeft=slider.scrollLeft});slider.addEventListener("mouseleave",()=>{isDown=false;slider.classList.remove("active")});slider.addEventListener("mouseup",()=>{isDown=false;slider.classList.remove("active")});slider.addEventListener("mousemove",e=>{if(!isDown)return;e.preventDefault();const x=e.pageX-slider.offsetLeft;const walk=(x-startX)*3;slider.scrollLeft=scrollLeft-walk;console.log(walk)})})});document.addEventListener("DOMContentLoaded",event=>{const faqs=document.querySelectorAll(".rank-math-list-item");faqs.forEach(faq=>{const question=faq.querySelector(".rank-math-question");question.addEventListener("click",()=>{faq.classList.toggle("active")})})});wp.domReady(()=>{wp.blocks.registerBlockStyle("core/list",[{name:"default",label:"Default",isDefault:true},{name:"separator-list",label:"Separador"},{name:"arrow-list",label:"Flecha simple"},{name:"arrow-separator-list",label:"Flecha con separador"},{name:"arrow-mini-separator-list",label:"Flecha mini con separador"},{name:"check-separator-list",label:"Check con separador"},{name:"check-list",label:"Check simple"}]);wp.blocks.registerBlockStyle("core/button",[{name:"default",label:"Default",isDefault:true},{name:"with-arrow",label:"Con Flecha"},{name:"outline-with-arrow",label:"Contorno con Flecha"}]);wp.blocks.registerBlockStyle("core/paragraph",[{name:"default",label:"Default",isDefault:true},{name:"title-has-image",label:"Imagen integrada"}]);wp.blocks.registerBlockStyle("core/cover",[{name:"cover-contain-background",label:"Contain Background"}]);wp.blocks.registerBlockStyle("core/quote",[{name:"quote-card",label:"Card"}]);wp.blocks.registerBlockStyle("core/query",[{name:"is-related-posts",label:"Related by category"}]);wp.blocks.registerBlockStyle("core/group",[{name:"group-horizontal-scroll",label:"Horizontal scroll"},{name:"group-horizontal-scroll-btns",label:"Horizontal scroll with buttons"},{name:"margin-vertical",label:"Margin vertical (top & bottom 80px)"}]);wp.blocks.registerBlockVariation("core/group",[{name:"group-horizontal-scroll",title:"Horizontal scroll group",icon:"leftright",description:"Items in Horizontal scroll",isDefault:false,atttibutes:{className:"is-style-group-horizontal-scroll"}}]);wp.blocks.registerBlockVariation("core/group",[{name:"group-horizontal-scroll-btns",title:"Horizontal scroll group with buttons",icon:"sort",description:"Items in Horizontal scroll with buttons",isDefault:false,atttibutes:{className:"is-style-group-horizontal-scroll--btns"}}])});wp.data.subscribe(function(){setTimeout(function(){const spacerBlocks=document.querySelectorAll(".wp-block.wp-block-spacer");for(let item=0;item<spacerBlocks.length;item++){const block=spacerBlocks[item];const style=getComputedStyle(block),height=parseInt(style.height)||0;block.querySelector(".components-resizable-box__container").setAttribute("data-spaceheight",height+"px")}},1)});wp.data.subscribe(function(){setTimeout(function(){const hiddenBlocks=document.querySelectorAll('[class*="hidden-"]');hiddenBlocks.forEach(function(block){const hiddenClasses=Array.from(block.classList).filter(function(cls){return cls.startsWith("hidden-")});if(hiddenClasses.length>0){block.setAttribute("data-hidden-class",hiddenClasses.join(" "))}})},1)});document.addEventListener("DOMContentLoaded",function(){gsap.registerPlugin(ScrollTrigger);gsap.utils.toArray(".wp-block-cover__inner-container > * > *, .is-layout-flow > * > *, .wp-block-separator, #colophon, .grid-productos > *").forEach(function(element){gsap.from(element,{scrollTrigger:{trigger:element,start:"top 80%",end:"bottom 20%",toggleActions:"play none none none"},opacity:0,y:50,duration:.3})})});(function(){const siteNavigation=document.getElementById("site-navigation");if(!siteNavigation){return}const button=siteNavigation.getElementsByTagName("button")[0];if("undefined"===typeof button){return}const menu=siteNavigation.getElementsByTagName("ul")[0];if("undefined"===typeof menu){button.style.display="none";return}if(!menu.classList.contains("nav-menu")){menu.classList.add("nav-menu")}button.addEventListener("click",function(){siteNavigation.classList.toggle("toggled");if(button.getAttribute("aria-expanded")==="true"){button.setAttribute("aria-expanded","false")}else{button.setAttribute("aria-expanded","true")}});document.addEventListener("click",function(event){const isClickInside=siteNavigation.contains(event.target);if(!isClickInside){siteNavigation.classList.remove("toggled");button.setAttribute("aria-expanded","false")}});const links=menu.getElementsByTagName("a");const linksWithChildren=menu.querySelectorAll(".menu-item-has-children > a, .page_item_has_children > a");for(const link of links){link.addEventListener("focus",toggleFocus,true);link.addEventListener("blur",toggleFocus,true)}for(const link of linksWithChildren){link.addEventListener("touchstart",toggleFocus,false)}function toggleFocus(){if(event.type==="focus"||event.type==="blur"){let self=this;while(!self.classList.contains("nav-menu")){if("li"===self.tagName.toLowerCase()){self.classList.toggle("focus")}self=self.parentNode}}if(event.type==="touchstart"){const menuItem=this.parentNode;event.preventDefault();for(const link of menuItem.parentNode.children){if(menuItem!==link){link.classList.remove("focus")}}menuItem.classList.toggle("focus")}}})();
